package sn.gestionimmobiliere.backend.dashboard.application;
import java.util.UUID;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import sn.gestionimmobiliere.backend.billing.infrastructure.RentChargeRepository;import sn.gestionimmobiliere.backend.dashboard.api.DashboardResponse;import sn.gestionimmobiliere.backend.lease.domain.LeaseStatus;import sn.gestionimmobiliere.backend.lease.infrastructure.LeaseRepository;import sn.gestionimmobiliere.backend.owner.application.OwnerProperties;import sn.gestionimmobiliere.backend.owner.infrastructure.OwnerRepository;import sn.gestionimmobiliere.backend.property.infrastructure.PropertyRepository;import sn.gestionimmobiliere.backend.tenant.infrastructure.TenantRepository;import sn.gestionimmobiliere.backend.unit.infrastructure.UnitRepository;
@Service public class DashboardService{private final OwnerRepository owners;private final PropertyRepository properties;private final UnitRepository units;private final TenantRepository tenants;private final LeaseRepository leases;private final RentChargeRepository charges;private final OwnerProperties props;public DashboardService(OwnerRepository o,PropertyRepository p,UnitRepository u,TenantRepository t,LeaseRepository l,RentChargeRepository c,OwnerProperties pr){owners=o;properties=p;units=u;tenants=t;leases=l;charges=c;props=pr;}@Transactional(readOnly=true)public DashboardResponse summary(){UUID org=props.organizationId();long expected=charges.totalDue(org);long collected=charges.totalPaid(org);return new DashboardResponse(owners.countByOrganizationIdAndDeletedAtIsNull(org),properties.countByOrganizationIdAndDeletedAtIsNull(org),units.countByOrganizationIdAndDeletedAtIsNull(org),tenants.countByOrganizationIdAndDeletedAtIsNull(org),leases.countByOrganizationIdAndStatus(org,LeaseStatus.ACTIVE),expected,collected,expected-collected);}}
